VALUES
  ('cpa-moex-01735', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '25，水上公司之功能性貨幣為日幣，水上公司X8年度保留盈餘換算資料如下： 日幣  匯率 新臺幣 期初保留盈餘餘額    ￥2,000,000 0.25 $500,000 X8年淨利    1,000,000 -- 260,000 X8年股利    (200,000) 0.28 (56,000) 期末保留盈餘餘額    ￥2,800,000 $704,000 光華公司X8年度權益法下因換算水上公司報表，帳上借記換算調整數$8,000，則光華公司X8年底 合併資產負債表上非控制權益餘額為何？', '["$283,200", "$386,800", "$388,800", "$390,800"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 0, "answer_corrected": false, "flags": ["answer_missing"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01736', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '臺北總公司以成本加價30%作為對分公司商品移轉之價格。X7年10月23日總公司運送成本$500,000 之商品給嘉義分公司，並另支付$15,000之運費。X7年11月15日臺南分公司向臺北總公司訂貨， 但由於存貨短缺，故由嘉義分公司將上述商品全數運往臺南分公司，並由嘉義分公司支付運費$7,700。 正常情況下，總公司運往臺南分公司之商品運費為$17,000，試計算臺南分公司於X7年11月15日 應認列之商品成本為多少？', '["$515,000", "$517,000", "$667,000", "$682,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01737', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', 'X7年底臺北總公司與分公司間往來之相關資料如下： ⑴總公司調整前帳上「分公司往來」餘額為$189,500。 ⑵分公司於X7年12月31日寄出$6,000之支票予總公司，總公司至X8年1月3日才收到。 ⑶總公司於X7年12月31日運送商品給分公司，分公司至X8年1月4日才收到。此批商品移轉價 格為$20,000。 ⑷分公司於X7年12月25日代收總公司應收帳款$1,500，但未通知總公司。 試問分公司調整前帳上「總公司往來」餘額為何？', '["$165,000", "$185,000", "$205,000", "$217,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01738', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '乙公司於重整期間以帳面金額$1,000,000，公允價值$1,200,000 之土地，清償帳面金額$2,000,000 之 無擔保負債，則應認列之債務清償損益為：', '["$800,000列本期損益", "$1,000,000列本期其他綜合損益", "$800,000列資本公積", "$1,000,000列非常損益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01739', 'cpa', 'cpa-moex-101-1cd83735', 'sub-cpa-06', NULL, 'single_choice', '若破產計畫表（statement of affairs）顯示，無擔保債務之償付比例為105%，下列敘述何者正確？', '["受擔保之債權人獲償金額將超過其債權之帳面金額", "無擔保之債權人獲償金額將超過其債權之 帳面金額", "股東可預期權益將有所回收", "僅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "4dea3e1911c4", "answer_pdf_sha1": "efb343389e4e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "高等會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01740', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '股份有限公司募集普通公司債，應經公司何一機關決議後，始得為之？', '["董事會", "股東會", "監察人", "審計委員會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01741', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者不屬於監察人得行使之權限？', '["監督公司業務之執行", "得出席董事會陳述意見，必要時得行使否決權", "得請求經理人提出報告", "得隨時調查公司業務及財務狀況，查核簿冊文件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01742', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '股份有限公司採募集設立方式成立時，發起人所認股份數至少應達第一次發行股份數之何種比例？', '["二分之一以上", "三分之一以上", "四分之一以上", "沒有限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01743', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '有關公司經理人競業禁止之規定，下列敘述何者錯誤？', '["不得兼任其他營利事業之經理人", "不得自營或為他人經營同類之業務", "有限公司經全體董事過半數同意者，可不受競業禁止之限制", "股份有限公司經董事會以董事過半數之出席，及出席董事過半數同意之決議行之者，可不受競業禁止 之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01744', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '經理人得為以下何種行為？', '["在公司章程或契約之授權範圍內，為公司管理事務及對外簽訂契約", "為其配偶之利益，從事與公司具有競爭性質之商業行為", "認為董事會決議為不智之舉，未經董事會知悉而自行改變董事會決議內容並予以執行", "未經公司同意而以公司資金支付自己之房屋貸款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01745', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '有限公司之董事如欲轉讓其出資之一部於他人時，應依下列何種方式？', '["獲得其他二分之一股東同意", "獲得三分之二股東同意", "獲得其他三分之二股東同意", "獲得其他全體股東同意"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01746', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲、乙、丙、丁及戊分別為A股份有限公司之董事，己則為甲之長子，居住於國內，亦為該公司之股東。 如該公司章程訂定董事會開會時，董事得委託他人代理出席，下列敘述何者正確？', '["甲如無法出席董事會時，可出具委託書，並列舉召集事由之授權範圍，經常委託其長子己代理出席", "丙可同時受甲及乙之委託，而代理出席董事會", "如甲居住國外，得以書面委託其長子己，經常代理出席董事會", "董事會開會時，如以視訊會議為之，其董事得以視訊參與會議，但不得視為親自出席"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01747', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司減資時，股東於公司所定期限內不換取股票者，其法律效果為何？', '["喪失其股東權利", "其股份無表決權", "對公司負損害賠償責任", "1年內不得轉讓其股份"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01748', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '三國天下股份有限公司之章程授權資本額為1,000萬元，已實收100萬元，尚未辦理公開發行，若為進行 投資於「五十風泡沫紅茶股份有限公司」，須投入50萬元，下列轉投資行為，何者合法？', '["若三國天下股份有限公司之章程已有規定轉投資不受公司法第13條之限制者，經董事會決議即可進行 轉投資", "若三國天下股份有限公司之章程並未解除公司法第13條轉投資之限制者，則須經股東表決權二分之一 以上出席，出席股東表決權二分之一以上之同意，始可進行轉投資", "若三國天下股份有限公司之章程並未解除公司法第13條轉投資之限制者，則須經董事及監察人聯席會 議全體同意，始可進行轉投資", "若三國天下股份有限公司之章程並未解除公司法第13條轉投資之限制者，則須經主管機關之核准始可 進行轉投資"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01749', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列敘述何者錯誤？', '["發起人之股份於公司設立登記後1年內不得轉讓", "公司股份之轉讓，不得於公司設立登記前為之", "員工分紅入股時，公司得限制其於一定時間內不得轉讓", "員工認股權憑證可以繼承"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01750', 'cpa', 'cpa-moex-100-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '如甲公司召開股東會時，得採行以書面或電子方式行使其表決權，則下列對其行使表決權之敘述何者正 確？', '["股東以書面或電子方式行使表決權者，其意思表示應於股東會開會2日前送達公司", "股東以書面或電子方式行使表決權後，欲親自出席股東會者，至遲應於股東會開會當日主席宣布開會 前，以與行使表決權相同之方式撤銷其書面或電子方式行使表決權之意思表示；逾期撤銷者，以書面 或電子方式行使之表決權為準", "股東以書面或電子方式行使表決權，並以委託書委託代理人出席股東會者，以其時間在先者為準", "以書面或電子方式行使表決權之股東，視為親自出席股東會。但就該次股東會之臨時動議及原議案之 修正，視為未出席"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:17+00:00", "source_pdf_sha1": "0c9e94347f27", "answer_pdf_sha1": "4c530c00988e", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
